  decorators: [
    (Story) => {
      for (const id of ['modal']) {
        if (!document.getElementById(id)) {
          const el = document.createElement('div')
          el.id = id
          document.body.appendChild(el)
        }
      }
      return (
        <MemoryRouter>
          <StoreProvider store={store}>
            <ThemeProvider theme={lightTheme}>
              <GlobalStyle />
              <Story />
            </ThemeProvider>
